import{_ as i,o as a,c as t,a6 as n}from"./chunks/framework.DtxWasON.js";const c=JSON.parse('{"title":"Total Supply","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/total-supply.md","filePath":"mainchain/introduction/total-supply.md"}'),e={name:"mainchain/introduction/total-supply.md"};function l(p,s,o,r,h,u){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="total-supply" tabindex="-1">Total Supply <a class="header-anchor" href="#total-supply" aria-label="Permalink to &quot;Total Supply&quot;">​</a></h1><p>The command</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supply</span></span></code></pre></div><p>Will return:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120486680721900000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  denom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nund</span></span></code></pre></div><p>The equivalent REST query is at the enpoint <code>/mainchain/enterprise/v1/supply</code> - for example:</p><ul><li>TestNet public REST server <a href="https://rest-testnet.unification.io/mainchain/enterprise/v1/supply" target="_blank" rel="noreferrer">https://rest-testnet.unification.io/mainchain/enterprise/v1/supply</a></li><li>MainNet public REST server <a href="https://rest.unification.io/mainchain/enterprise/v1/supply" target="_blank" rel="noreferrer">https://rest.unification.io/mainchain/enterprise/v1/supply</a></li></ul><div class="danger custom-block"><p class="custom-block-title">IMPORTANT!!!</p><p>the <code>/mainchain/enterprise/v1/supply</code> endpoint <strong>MUST</strong> be used instead of <code>/cosmos/bank/v1beta1/supply</code> to get true total supply available for general use, i.e. with locked eFUND removed from total</p></div><p>The command</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enterprise</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ent-supply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=PROTOCOL://NODE_IP:PORT</span></span></code></pre></div><p>Will return the complete supply information.</p><p>The equivalent REST query is at the enpoint <code>/mainchain/enterprise/v1/ent_supply</code> - for example:</p><ul><li>TestNet public REST server <a href="https://rest-testnet.unification.io/mainchain/enterprise/v1/ent_supply" target="_blank" rel="noreferrer">https://rest-testnet.unification.io/mainchain/enterprise/v1/ent_supply</a></li><li>MainNet public REST server <a href="https://rest.unification.io/mainchain/enterprise/v1/ent_supply" target="_blank" rel="noreferrer">https://rest.unification.io/mainchain/enterprise/v1/ent_supply</a></li></ul><p>Three quantity values are returned, all representing <code>nund</code>:</p><ol><li><strong>amount</strong>: Liquid FUND in active circulation, and the actual circulating total supply which is available and can be used for FUND transfers, staking, Tx fees etc. It is the <strong>locked</strong> amount subtracted from <strong>total</strong>. <em>This is the important value when processing any calculations dependent on FUND circulation/total supply of FUND etc.</em></li><li><strong>locked</strong>: Total FUND locked through Enterprise purchases. This FUND is only available specifically to pay WRKChain / BEACON fees and <strong>cannot</strong> be used for transfers, staking/delegation or any other transactions. <em>Locked FUND only enters the active circulation supply once it has been used to pay for WRKChain / BEACON fees. Until then, it is considered &quot;dormant&quot;, and <strong>not</strong> part of the circulating total supply</em></li><li><strong>total</strong>: The total amount of FUND currently known on the chain, including any Enterprise <strong>locked</strong> FUND. This is for informational purposes only and should not be used for any &quot;circulating/total supply&quot; calculations.</li></ol><p>The <strong>amount</strong> value is the important value regarding total supply <em>currently in active circulation</em>, and is the information that should be used to represent any &quot;total supply/circulation&quot; values for example in block explorers, wallets, exchanges etc.</p><p>Consider the following <code>und query enterprise ent-supply</code> result:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">supply</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120010263000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  denom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nund</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  locked</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;89737000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  total</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120100000000000000&quot;</span></span></code></pre></div><p>Or, the equivalent REST query result:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;supply&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;denom&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nund&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;amount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120010263000000000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;locked&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;89737000000000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;total&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120100000000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>In the above example, the active circulating supply - usable for transfers and standard transactions etc. - is currently 120,010,263 FUND. 89,737 FUND is currently locked, and can only be used for paying for WRKChain/BEACON fees - it is &quot;dormant&quot; and <em>cannot be used for any other purpose until it has been used to pay for WRKChain/BEACON fees, and therefore <strong>does not count towards total circulating supply</strong></em>. Finally, the total amount of FUND known on the chain including locked is 120,100,000 FUND, and is the equivalent of 120,010,263 + 89,737.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>The REST endpoint <code>/mainchain/enterprise/v1/supply/nund</code> will return only the appropriate <strong>amount</strong> value, for example on <strong>TestNet</strong>, <a href="https://rest-testnet.unification.io//mainchain/enterprise/v1/supply/nund" target="_blank" rel="noreferrer">https://rest-testnet.unification.io/mainchain/enterprise/v1/supply/nund</a> would just return</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;amount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;denom&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nund&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;amount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120486721721900000&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></div><h2 id="converting-to-fund" tabindex="-1">Converting to FUND <a class="header-anchor" href="#converting-to-fund" aria-label="Permalink to &quot;Converting to FUND&quot;">​</a></h2><p>In much the same way that Ethereum uses <code>wei</code> and Cosmos uses <code>uatom</code> as the smallest on-chain denomination, all results for Unification Mainchain return the native on-chain coin denomination values in <code>nund</code>. <strong>1,000,000,000 nund == 1 FUND</strong>. As such, simply dividing the result by 1000000000 will yield the FUND value.</p><p>See <a href="./denomination.html">denomination</a> for further information.</p><p>See <a href="./../software/und_cmd/und_query_supply.html">und-query-supply</a> for more details on command flags and parameters.</p>`,26)])])}const k=i(e,[["render",l]]);export{c as __pageData,k as default};
